const chatId = (trigger.message?.chat?.id || trigger.callback_query?.message?.chat?.id)?.toString() || "";
const telegramId = (trigger.message?.from?.id || trigger.callback_query?.from?.id)?.toString() || "";
const texto = (trigger.callback_query?.data || trigger.message?.text || '').trim();
const numero = parseInt(texto);

const todasLasSesiones = $('Leer Sesión Usuario').all();
const session = todasLasSesiones.find(s => String(s.json.telegram_id) === telegramId)?.json;

if (!session) {
    return [{ json: { accion: "error", chatId, mensaje: "No se encontró tu sesión." } }];
}

const catalogo = $('Leer Menú Completo Producto').all(); 

let productos = [];
try {
    const raw = session.productos || session.producto_seleccionado;
    productos = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch(e) { productos = []; }

if (numero === 0) {
    return [{ json: { accion: "volver", chatId, mensaje: "💠 *MENÚ PRINCIPAL*..." } }];
}

if (isNaN(numero) || numero < 1 || numero > productos.length) {
    return [{ json: { accion: "error", chatId, mensaje: `⚠️ Opción no válida.` } }];
}

const p = productos[numero - 1];


const productoReal = catalogo.find(item => item.json.id === p.id || item.json.nombre === p.nombre);
const stockDisponible = productoReal ? (productoReal.json.stock || 0) : 0;

const precioBase = Number(p.precio) || 0;
const ivaUnitario = Math.round(precioBase * 0.19);
const precioTotalUnitario = precioBase + ivaUnitario;

const formatoCOP = (precio) => new Intl.NumberFormat('es-CO', { style: 'currency', currency: 'COP', minimumFractionDigits: 0 }).format(Number(precio) || 0);

return [{
  json: {
    accion: "pedir_cantidad",
    chatId: chatId,
    pantalla_actual: session.pantalla_actual,
    productoElegido: JSON.stringify({ ...p, stock: stockDisponible }),
    mensaje: `💠 *CONFIRMACIÓN DE PEDIDO*\n` +
             `━━━━━━━━━━━━━━━━━━━━━\n` +
             `📍 Producto: *${(p.nombre || "Producto").toUpperCase()}*\n` +
             `💸 Precio base: ${formatoCOP(precioBase)}\n` +
             `📊 IVA (19%): ${formatoCOP(ivaUnitario)}\n` +
             `💰 *Total unitario: ${formatoCOP(precioTotalUnitario)}*\n` +
             `📦 Stock disponible: ${stockDisponible}\n` + 
             `━━━━━━━━━━━━━━━━━━━━━\n\n` +
             `👉 *De querer salir, por favor utilice /start*\n` +
             `👉 *¿Cuántas unidades deseas llevar?*`
  }
}];

const trigger = $('Telegram Trigger').item.json;
const telegramId = String(trigger.message?.from?.id ?? "");
const textoUsuario = trigger.message?.text?.trim() ?? "";

const sesiones = $input.all();

const session = sesiones.find(s => String(s.json.telegram_id ?? "").trim() === telegramId)?.json;

const estaRegistrado = !!session;
const esStart = textoUsuario === '/start';
const puedeAcceder = estaRegistrado || esStart;

return [{ 
