    } 
}];

const trigger = $('Telegram Trigger').item.json;
const chatId = (trigger.message?.chat?.id || trigger.callback_query?.message?.chat?.id)?.toString() || "";
const telegramId = (trigger.message?.from?.id || trigger.callback_query?.from?.id)?.toString() || "";
const texto = (trigger.message?.text || '').trim();
const cantidad = parseInt(texto);

const todasLasSesiones = $('Leer Sesión Usuario').all(); 
const session = todasLasSesiones.find(s => s.json.telegram_id?.toString() === telegramId)?.json;

if (!session) {
  return [{ json: { error: true, chatId, mensaje: "⚠️ No encontramos tu sesión. Escribe /start." } }];
}

let p = null;
try {
  // Si está vacío, no dispares error, simplemente marca como nulo
  if (session.producto_seleccionado && session.producto_seleccionado !== "") {
    p = typeof session.producto_seleccionado === 'string'
      ? JSON.parse(session.producto_seleccionado)
      : session.producto_seleccionado;
  }
} catch(e) {
  // Si hay error de formato, aquí sí es un error
  return [{ json: { error: true, chatId, mensaje: "⚠️ Formato de producto inválido." } }];
}

// SI p sigue siendo null, significa que el usuario nunca seleccionó nada
if (!p) {
  return [{ json: { error: true, chatId, mensaje: "⚠️ Por favor, selecciona un producto del menú antes de indicar la cantidad." } }];
}

let carrito = [];
try {
  carrito = typeof session.carrito_temporal === 'string'
    ? JSON.parse(session.carrito_temporal || "[]")
    : (session.carrito_temporal || []);
} catch(e) { carrito = []; }

if (isNaN(cantidad) || cantidad < 1) {
  return [{ json: { error: true, chatId, mensaje: "⚠️ Por favor, escribe un número válido mayor a 0." } }];
}

const stockDisponible = Number(p.stock) || 0;
if (cantidad > stockDisponible) {
  return [{ json: { error: true, chatId, mensaje: `🚫 *¡Stock insuficiente!*\nDisponible: ${stockDisponible}.\nPor favor, vuelva a escribir la cantidad deseada, o regrese con /start si asi lo desea.` } }];
}

const idx = carrito.findIndex(item => item.id === p.id);
if (idx >= 0) {
  carrito[idx].qty += cantidad;
} else {
  carrito.push({ id: p.id, nombre: p.nombre, precio: p.precio, qty: cantidad });
}

const subtotal = Number(p.precio) * cantidad;

const iva = Math.round(subtotal * 0.19);
const totalConIva = subtotal + iva;

const formatoCOP = (val) => new Intl.NumberFormat('es-CO', { 
  style: 'currency', currency: 'COP', minimumFractionDigits: 0 
}).format(val);

const mensaje = `✅ *¡Producto agregado al carrito!* 🛒\n` +
  `━━━━━━━━━━━━━━━━━━━━━\n` +
  `📍 *${cantidad}x* ${p.nombre}\n` +
  `💸 Subtotal: ${formatoCOP(subtotal)}\n` +
  `📊 IVA (19%): ${formatoCOP(iva)}\n` +
  `💰 *TOTAL: ${formatoCOP(totalConIva)}*\n` +
  `━━━━━━━━━━━━━━━━━━━━━\n\n` +
  `Para continuar, puedes escribir:\n` +
  `• *Ver carrito*\n` +
  `• *Confirmar*\n` +
  `• O el número de otra categoría para seguir comprando.`;

return [{
  json: { 
    error: false, 
    chatId, 
    mensaje,
    carritoJSON: JSON.stringify(carrito),
    categoria: session.categoria_seleccionada || ""
  } 
}];

const trigger = $('Telegram Trigger').item.json;
