let lineaPuntos = `\n━━━━━━━━━━━━━━━━━━━━━\n`;
lineaPuntos += `⭐ Tus puntos: *${puntosActuales} pts*\n`;

if (cuponesDisponibles.length > 0) {
  lineaPuntos += `🎟️ Tienes *${cuponesDisponibles.length}* cupón(es) disponible(s) — se aplicará automáticamente al confirmar.\n`;
} else {
  lineaPuntos += `🎯 Te faltan *${puntosParaSiguiente} pts* para tu próximo cupón de 10%.\n`;
}

if (carrito.length === 0) {
