            mensaje: "🛒 *Tu carrito está vacío.*\n\nElige una categoría para comenzar:\n1️⃣ Bebidas\n2️⃣ Comida\n3️⃣ Aperitivos\n4️⃣ Postres" + lineaPuntos
        }
    }];
}

let totalBase = 0; 
