    totalBase += subtotalItem;
    return `  • *${item.nombre}* x${item.qty} = $${subtotalItem.toLocaleString('es-CO')} COP`;
}).join('\n');

const valorIVA = Math.round(totalBase * 0.19);
const totalConIVA = totalBase + valorIVA;

const mensaje = `🛒 *TU CARRITO ACTUAL*\n\n${detalle}\n\n`
