    }
  }];
}

const problemas = [];
for (const item of carrito) {
  const productoMenu = menuItems.find(m => String(m.json.id_producto) === String(item.id));

  if (!productoMenu) {
    problemas.push({
      motivo: `El producto *${item.nombre || item.id}* ya no está disponible en el menú.`
    });
    continue;
  }

  const stockDisponible = Number(productoMenu.json.stock);
  const cantidadSolicitada = Number(item.qty);

  if (stockDisponible < cantidadSolicitada) {
