const hora = new Date().toLocaleTimeString('es-CO', { 
    timeZone: 'America/Bogota', 
    hour: '2-digit', 
    minute: '2-digit' 
});

const formatoCOP = (val) => `$${Math.round(val).toLocaleString('es-CO')} COP`;

let mensajeUsuario =
  `✅ *PEDIDO CONFIRMADO*\n` +
  `━━━━━━━━━━━━━━━━━━━━━\n` +
  `📋 Orden: \`${idPedido}\`\n\n` +
  `*Detalle:*\n${detalleTexto}\n` +
  `━━━━━━━━━━━━━━━━━━━━━\n` +
  `🧾 Subtotal:       ${formatoCOP(subtotalBase)}\n`;

if (descuentoAplicado > 0) {
  mensajeUsuario += `${lineaDescuento}`;
}

mensajeUsuario +=
  `📊 IVA (19%):      ${formatoCOP(valorIVA)}\n` +
  `💰 *TOTAL:         ${formatoCOP(totalFinal)}*\n` +
  `━━━━━━━━━━━━━━━━━━━━━\n` +
  `⭐ Puntos ganados: +${puntosGanados} pts\n` +
  `🏆 Total puntos:   ${puntosNuevos} pts\n`;
  `Cada 100pts se te generara un cupon para 10% en el total de tu compra!\n`;

if (generaCupon) {
  mensajeUsuario +=
    `\n🎉 *¡Desbloqueaste un cupón!*\n` +
    `🎟️ Código: \`${codigoCuponNuevo}\`\n` +
    `   Válido para 10% de descuento en tu próximo pedido.\n`;
}

mensajeUsuario +=
  `\n⏳ Estado: *Recibido*\n` +
  `Te notificaremos cuando avance tu pedido.`;

const mensajeCocina =
  `🔔 *NUEVO PEDIDO*\n\n` +
  `📋 Orden: \`${idPedido}\`\n` +
  `👤 Usuario: ${telegramId}\n\n` +
  `*Detalle:*\n${detalleTexto}\n` +
  `💰 Total: ${formatoCOP(totalFinal)}\n` +
  `🕐 ${fecha} ${hora}\n` +
  `De querer ajustar el estado del pedido, porfavor use /estado.`;

return [{
  json: {
    error: false,
    idPedido,
    telegramId,
    chatId,
    detallesJSON: JSON.stringify(carrito),
    subtotalBase,
    descuentoAplicado,
    codigoCuponUsado,       
    valorIVA,
    totalFinal,
    puntosGanados,
    puntosNuevos,           
    generaCupon,
    codigoCuponNuevo,       
    fecha,
    hora,
    mensajeUsuario,
    mensajeCocina
  }
}];

const datosPrevios = $('Procesar Confirmación Pedido').all(); 

if (!datosPrevios || datosPrevios.length === 0) {
    throw new Error("El nodo anterior no tiene datos.");
}

const data = datosPrevios[0].json;

console.log("Datos recibidos:", JSON.stringify(data));

let carrito = [];

if (Array.isArray(data.carrito)) {
    carrito = data.carrito;
} else if (typeof data.detallesJSON === 'string') {
    try {
        carrito = JSON.parse(data.detallesJSON);
    } catch(e) {
        carrito = [];
    }
}

return carrito.map(item => ({
  json: {
    id_producto: item.id || "N/A",
    nombre_producto: item.nombre || "Desconocido",
    qty_vendida: item.qty || 0,
    idPedido: data.idPedido || "Sin-ID",
    chatId: data.chatId,
    mensajeUsuario: data.mensajeUsuario,
    mensajeCocina: data.mensajeCocina
  }
}));

const msg = $input.first().json.message;
const texto = msg.text;
const adminId = msg.from.id;
const chatId = msg.chat.id.toString();

const ADMIN_ID = 8900800374;
const COCINA_CHAT_ID = "-5140257658";

const emojis = {
  "Recibido": "📋",
  "Preparación": "👨‍🍳",
  "En camino": "🛵",
  "Entregado": "✅"
};

const estadosValidos = Object.keys(emojis);

const listaEstados = estadosValidos
  .map(estado => `${emojis[estado]} ${estado}`)
  .join("\n");

const normalizar = (str) => str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase();

if (!texto.startsWith("/estado")) {
  return []; 
}

if (chatId !== COCINA_CHAT_ID) {
  return [{
    json: {
      esComando: true,
      chatId,
      esAdmin: false,
      mensajeError:
        "⛔ Los comandos administrativos solo funcionan en el grupo de cocina y con permisos de administrador."
    }
  }];
}

const partes = texto.replace("/estado", "").trim().split(/\s+/);

if (partes.length < 2) {
  return [{
    json: {
      esAdmin: adminId === ADMIN_ID,
      comandoValido: false,
      adminId,
      chatId,
      mensajeError:
`⚠️ Formato incorrecto.

Uso:
/estado ID_PEDIDO NUEVO_ESTADO

Estados válidos:
${listaEstados}`
    }
  }];
}

const idPedido = partes[0];
const nuevoEstadoRaw = partes.slice(1).join(" ");
const nuevoEstadoNormalizado = normalizar(nuevoEstadoRaw);

const estadoReal = estadosValidos.find(e => normalizar(e) === nuevoEstadoNormalizado);
const esEstadoValido = !!estadoReal;
const esAdmin = adminId === ADMIN_ID;
const emoji = estadoReal ? emojis[estadoReal] : "📦";

if (!esEstadoValido) {
  return [{
    json: {
      comandoValido: false,
      esAdmin,
      esEstadoValido: false,
      adminId,
      chatId,
      idPedido,
      nuevoEstado: nuevoEstadoRaw,
      mensajeEstadoInvalido:
`❌ Estado inválido: *${nuevoEstadoRaw}*

Estados permitidos:
${listaEstados}`
    }
  }];
}

return [{
  json: {
    chatId,
    comandoValido: true,
    idPedido,
    nuevoEstado: estadoReal,
    esAdmin,
    esEstadoValido,
    adminId,
    emoji,

    mensajeCliente:
`${emoji} *Tu pedido actualizó su estado*

📋 Orden: \`${idPedido}\`
Estado actual: ${emoji} *${estadoReal}*`,

    mensajeAdmin:
`✅ Estado de \`${idPedido}\` actualizado correctamente.\n\nNuevo estado: ${emoji} *${estadoReal}*`,

    mensajeEstadoInvalido:
`❌ Estado inválido: *${nuevoEstadoRaw}*

Estados permitidos:
${listaEstados}`
  }
}];

const listaPedidos = $('Leer Pedidos del Día').all().filter(i => i.json.id_pedido);
const menuItems = $('Leer Menú Reporte Diario').all();

const hoy = new Intl.DateTimeFormat('es-CO', {
  timeZone: 'America/Bogota',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric'
}).format(new Date());

if (listaPedidos.length === 0) {
  return [{
    json: {
      reporte: `📊 *Reporte diario — ${hoy}*\n\nNo se registraron pedidos hoy.`,
      adminId: 8900800374
    }
  }];
}

let totalVendido = 0;
const conteoProductos = {};
const conteoPorHora = {};
const usuariosUnicos = new Set();

for (const p of listaPedidos) {
  totalVendido += Number(p.json.total_pago) || 0;

  if (p.json.telegram_id) usuariosUnicos.add(p.json.telegram_id);

  let detalles = [];
  try { 
    detalles = typeof p.json.detalles_pedido === 'string' 
      ? JSON.parse(p.json.detalles_pedido) 
      : (p.json.detalles_pedido || []); 
  } catch(e) {}

  for (const item of detalles) {
    conteoProductos[item.id] = (conteoProductos[item.id] || 0) + Number(item.qty || 1);
  }

  const hora = (p.json.hora || "00:00").split(":")[0];
  conteoPorHora[hora] = (conteoPorHora[hora] || 0) + 1;
}

const topProductoEntry = Object.entries(conteoProductos).sort((a, b) => b[1] - a[1])[0];
let productoEstrella = "Sin datos";

if (topProductoEntry) {
  const idEstrella = topProductoEntry[0];
  const cantidadEstrella = topProductoEntry[1];
  const productoMenu = menuItems.find(m => String(m.json.id_producto) === String(idEstrella));
  productoEstrella = `${productoMenu ? productoMenu.json.nombre : idEstrella} (${cantidadEstrella} uds.)`;
}

const totalPedidos = listaPedidos.length;
const horaPicoEntry = Object.entries(conteoPorHora).sort((a, b) => b[1] - a[1])[0];
const horaPico = horaPicoEntry ? `${horaPicoEntry[0]}:00 (${horaPicoEntry[1]} pedidos)` : "Sin datos";
const ticketPromedio = totalPedidos > 0 ? Math.round(totalVendido / totalPedidos) : 0;

const reporte =
  `📊 *Reporte diario — ${hoy}*\n`
  + `━━━━━━━━━━━━━━━━━━━━━━\n`
  + `📦 Total de pedidos:    *${totalPedidos}*\n`
  + `💰 Total vendido:       *$${totalVendido.toLocaleString('es-CO')} COP*\n`
  + `🧾 Ticket promedio:     *$${ticketPromedio.toLocaleString('es-CO')} COP*\n`
  + `⭐ Producto estrella:   *${productoEstrella}*\n`
  + `🕐 Hora pico:           *${horaPico}*\n`
  + `👥 Usuarios únicos:     *${usuariosUnicos.size}*\n`
  + `━━━━━━━━━━━━━━━━━━━━━━\n`
  + `🤖 Generado automáticamente por DeliveryBot`;

return [{ json: { reporte, adminId: 8900800374 } }];
